mapper.insert:
INSERT INTO ImageBoard(
	ImageNo
	, ImageTitle
	, UserId
	, ImageContent
	, ImageDate)
VALUES (
	Image_SEQ.NEXTVAL
	, #{ImageTitle}
	, #{UserId}
	, #{ImageContent}
	, sysdate
	)

INSERT INTO ImageData(
	ImageData
	, ImageNo
	, OldName
	, ImageStep)
VALUES(
	#{ImageData}
	, Image_SEQ.CURRVAL
	, #{OldName}
	, #{ImageStep}
)

mapper.select:
